        DATE_TRUNC(''month'', order_date) as month,
        COUNT(*) as order_count,
        SUM(total_amount) as total_revenue
    FROM sales_orders 
    WHERE order_date >= CURRENT_DATE - INTERVAL ''12 months''
    GROUP BY DATE_TRUNC(''month'', order_date)
    ORDER BY month', '{"type":"line","xAxis":"month","yAxis":"total_revenue","showLegend":true}', 'sales', '2025-06-04T17:17:13.453Z', '2025-06-04T17:17:13.453Z', true);
        c.name as customer_name,
        COUNT(so.id) as order_count,
        SUM(so.total_amount) as total_revenue
    FROM customers c
    JOIN sales_orders so ON c.id = so.customer_id
    GROUP BY c.id, c.name
    ORDER BY total_revenue DESC
    LIMIT 10', '{"type":"bar","xAxis":"customer_name","yAxis":"total_revenue","showLegend":false}', 'sales', '2025-06-04T17:17:13.453Z', '2025-06-04T17:17:13.453Z', true);
        cat.name as category_name,
        COUNT(m.id) as material_count,
        SUM(inv.quantity) as total_quantity
    FROM categories cat
    JOIN materials m ON cat.id = m.category_id
    JOIN inventory inv ON m.id = inv.material_id
    GROUP BY cat.id, cat.name
    ORDER BY total_quantity DESC', '{"type":"pie","dataKey":"total_quantity","nameKey":"category_name","showLegend":true}', 'inventory', '2025-06-04T17:17:13.453Z', '2025-06-04T17:17:13.453Z', true);
        cc.name as cost_center,
        SUM(e.amount) as total_expenses
    FROM cost_centers cc
    LEFT JOIN expenses e ON cc.id = e.cost_center_id
    WHERE e.expense_date >= DATE_TRUNC(''year'', CURRENT_DATE)
    GROUP BY cc.id, cc.name
    ORDER BY total_expenses DESC', '{"type":"bar","xAxis":"cost_center","yAxis":"total_expenses","showLegend":false}', 'finance', '2025-06-04T17:17:13.453Z', '2025-06-04T17:17:13.453Z', true);
        v.name as vendor_name,
        COUNT(po.id) as order_count,
        SUM(po.total_amount) as total_amount
    FROM vendors v
    JOIN purchase_orders po ON v.id = po.vendor_id
    WHERE po.order_date >= CURRENT_DATE - INTERVAL ''6 months''
    GROUP BY v.id, v.name
    ORDER BY total_amount DESC
    LIMIT 10', '{"type":"bar","xAxis":"vendor_name","yAxis":"total_amount","showLegend":false}', 'purchase', '2025-06-04T17:17:13.453Z', '2025-06-04T17:17:13.453Z', true);


