INSERT INTO "coach_agents" ("id", "name", "role", "responsibilities", "oversight_scope", "decision_authority", "cross_domain_knowledge", "status", "is_active", "created_at", "updated_at") VALUES ('0dbd4201-e841-4157-8aac-d2fff74947dc', 'System Coach Agent', 'system_coach', '{"oversight":["Monitor all Player Agent activities","Review and approve configuration change requests","Provide cross-domain business justification","Ensure enterprise-wide consistency","Manage agent access controls","Coordinate inter-domain business processes"],"communication":["Provide guidance to Player Agents","Explain cross-domain implications","Document decision rationale","Facilitate business domain coordination"],"decisionMaking":["Approve/reject data modification requests","Authorize UI changes based on business impact","Set configuration standards across domains","Resolve cross-domain conflicts","Establish compliance policies"]}', '{"businessDomains":["sales","finance","inventory","procurement","manufacturing","controlling"],"systemComponents":["database","ui","configuration","master_data","transactions"],"crossDomainProcesses":["order_to_cash","procure_to_pay","plan_to_produce","record_to_report"]}', '{"dataChanges":{"level":"full_authority","scope":"all_business_domains","requiresJustification":true},"uiModifications":{"level":"full_authority","scope":"all_interfaces","requiresBusinessCase":true},"configurationChanges":{"level":"full_authority","scope":"enterprise_wide","requiresCrossDomainAnalysis":true},"accessControlManagement":{"level":"exclusive_authority","scope":"all_agents","adminOnly":true}}', '{"controllingIntegration":{"processes":["profitability_analysis","cost_center_accounting","internal_orders"],"keyIntegrationPoints":["all_business_domains"]},"salesFinanceIntegration":{"processes":["revenue_recognition","credit_management","pricing_controls"],"keyIntegrationPoints":["customer_master","payment_terms","credit_limits"]},"manufacturingIntegration":{"processes":["cost_absorption","wip_valuation","capacity_planning"],"keyIntegrationPoints":["bom_costing","work_centers","production_orders"]},"inventoryFinanceIntegration":{"processes":["valuation_methods","cost_allocation","variance_analysis"],"keyIntegrationPoints":["material_master","standard_costs","inventory_accounts"]},"procurementFinanceIntegration":{"processes":["three_way_matching","accrual_accounting","vendor_payments"],"keyIntegrationPoints":["vendor_master","purchase_commitments","ap_accounts"]}}', 'active', true, '2025-06-07T14:57:57.302Z', '2025-06-07T14:57:57.302Z');
INSERT INTO "coach_decisions" ("id", "coach_agent_id", "change_request_id", "decision_type", "decision_summary", "cross_domain_analysis", "project_justification", "affected_domains", "risk_mitigation", "implementation_guidance", "follow_up_required", "follow_up_date", "decision_impact", "created_at", "updated_at") VALUES ('71f66da5-689e-41a9-83a5-b1ec20a13a05', '0dbd4201-e841-4157-8aac-d2fff74947dc', '836cd806-610b-46c2-880a-aa8d3251b6a8', 'change_approval', 'APPROVED: APPROVED: Temporary credit limit increases during promotional campaigns align with business growth objectives. Cross-domain analysis shows manageable risk with proper controls. Finance domain impact is acceptable given enhanced monitoring protocols. Controlling domain benefits from improved cash flow visibility during campaigns. Implementation includes automatic reversion safeguards which mitigate long-term risk exposure.', '{"impact":"medium","riskMitigation":{"approach":"phased_rollout","controls":["automatic_expiration","enhanced_monitoring","approval_workflows"],"fallback":"immediate_reversion_capability"},"affectedDomains":["sales","finance","controlling","inventory"],"businessBenefits":{"sales":"Increased deal closure rate, enhanced customer satisfaction","finance":"Improved revenue recognition, controlled risk exposure","controlling":"Better campaign ROI tracking, enhanced profitability analysis"},"enterpriseAlignment":"Supports quarterly growth targets while maintaining financial discipline"}', 'APPROVED: Temporary credit limit increases during promotional campaigns align with business growth objectives. Cross-domain analysis shows manageable risk with proper controls. Finance domain impact is acceptable given enhanced monitoring protocols. Controlling domain benefits from improved cash flow visibility during campaigns. Implementation includes automatic reversion safeguards which mitigate long-term risk exposure.', '{"sales","finance","controlling","inventory"}', '{"approach":"phased_rollout","controls":["automatic_expiration","enhanced_monitoring","approval_workflows"],"fallback":"immediate_reversion_capability"}', '{"phase1":"Configure temporary credit override fields with expiration logic","phase2":"Implement enhanced approval workflows for increases >25%","phase3":"Deploy automated monitoring and reversion processes","timeline":"72 hours","rollbackPlan":"Immediate disable override functionality if risk thresholds exceeded"}', true, '2025-06-14T15:00:25.729Z', 'medium', '2025-06-07T15:00:25.738Z', '2025-06-07T15:00:25.738Z');
