 scheduling","12. Invoice INV-DOM-001: Complete billing with payment confirmation"],"flowName":"Complete Dominos Pizza Order-to-Cash Flow","testDate":"2025-06-09","businessMetrics":{"orderValue":"$35.43","grossProfit":"$16.53","avgOrderTime":"30 minutes","taxCollected":"$2.47","salesChannels":3,"customersServed":2,"deliveryOptions":3,"deliveryRevenue":"$2.99","productsOffered":3,"paymentSuccessRate":"100%","productionFacilities":3,"operationalEfficiency":"100%","totalProductionCapacity":"1,850 pizzas/hour","customerSatisfactionTarget":"95%"},"integrationPoints":{"taxCalculation":"Automated","paymentIntegration":"Processed","pricingIntegration":"Active","deliveryIntegration":"Scheduled","inventoryIntegration":"Real-time","accountingIntegration":"Posted","masterDataIntegration":"Complete"}}}', 'DOM01', '2025-06-09T12:51:03.051Z', 'CONN-1749482204.945000', 'CONN-1749482204.945000');
