INSERT INTO "tile_naming_documentation" ("id", "alphabetic_prefix", "prefix_name", "description", "number_range", "process_logic", "customized_prefix", "examples", "business_justification", "created_at", "updated_at") VALUES (1, 'A', 'Master Data (Organizational)', 'Fundamental organizational setup including company structure, plants, and financial framework', 'A001-A099', 'Sequential implementation order: Company Code → Chart of Accounts → Plant → Storage Location → GL Accounts → Cost Centers', 'AC', '{[object Object],[object Object],[object Object]}', 'Organizational master data forms the foundation of all business processes and must be implemented in logical sequence', '2025-06-06T17:16:20.865Z', '2025-06-06T17:16:20.865Z');
INSERT INTO "tile_naming_documentation" ("id", "alphabetic_prefix", "prefix_name", "description", "number_range", "process_logic", "customized_prefix", "examples", "business_justification", "created_at", "updated_at") VALUES (2, 'B', 'Business Partner Master', 'Customer and vendor master data for sales and procurement processes', 'B001-B099', 'Partner setup order: Customers first (revenue focus), then Vendors (cost management)', 'BC', '{[object Object],[object Object]}', 'Business partners are essential for all transactional processes and should be established early in implementation', '2025-06-06T17:16:20.865Z', '2025-06-06T17:16:20.865Z');
INSERT INTO "tile_naming_documentation" ("id", "alphabetic_prefix", "prefix_name", "description", "number_range", "process_logic", "customized_prefix", "examples", "business_justification", "created_at", "updated_at") VALUES (3, 'C', 'Material Master', 'Product and material information for inventory and production management', 'C001-C099', 'Material data forms the basis for all inventory, production, and sales processes', 'CC', '{[object Object]}', 'Material master data is referenced across sales, procurement, production, and financial processes', '2025-06-06T17:16:20.865Z', '2025-06-06T17:16:20.865Z');
INSERT INTO "tile_naming_documentation" ("id", "alphabetic_prefix", "prefix_name", "description", "number_range", "process_logic", "customized_prefix", "examples", "business_justification", "created_at", "updated_at") VALUES (4, 'S', 'Sales Process', 'Order-to-cash business process from customer inquiry to payment receipt', 'S001-S099', 'Document flow: Sales Order → Delivery → Billing → Payment Receipt', 'SC', '{[object Object],[object Object],[object Object]}', 'Sales process drives revenue generation and customer satisfaction through systematic order fulfillment', '2025-06-06T17:16:20.865Z', '2025-06-06T17:16:20.865Z');
INSERT INTO "tile_naming_documentation" ("id", "alphabetic_prefix", "prefix_name", "description", "number_range", "process_logic", "customized_prefix", "examples", "business_justification", "created_at", "updated_at") VALUES (5, 'P', 'Procurement Process', 'Purchase-to-pay business process from requirement to vendor payment', 'P001-P099', 'Document flow: Purchase Order → Goods Receipt → Invoice Verification → Payment', 'PC', '{[object Object],[object Object],[object Object]}', 'Procurement process ensures cost-effective sourcing and supplier relationship management', '2025-06-06T17:16:20.865Z', '2025-06-06T17:16:20.865Z');
INSERT INTO "tile_naming_documentation" ("id", "alphabetic_prefix", "prefix_name", "description", "number_range", "process_logic", "customized_prefix", "examples", "business_justification", "created_at", "updated_at") VALUES (6, 'F', 'Finance Process', 'Financial accounting, payments, and cash management', 'F001-F099', 'Financial process flow: Invoice Processing → Payment Processing → Cash Management → Financial Reporting', 'FC', '{[object Object],[object Object],[object Object]}', 'Finance processes ensure accurate financial reporting and effective cash flow management', '2025-06-06T17:16:20.865Z', '2025-06-06T17:16:20.865Z');
INSERT INTO "tile_naming_documentation" ("id", "alphabetic_prefix", "prefix_name", "description", "number_range", "process_logic", "customized_prefix", "examples", "business_justification", "created_at", "updated_at") VALUES (7, 'I', 'Inventory Management', 'Stock movements, warehouse operations, and inventory optimization', 'I001-I099', 'Inventory flow: Goods Issue → Stock Transfer → Inventory Counting → Valuation', 'IC', '{[object Object],[object Object]}', 'Inventory management optimizes stock levels and ensures material availability for operations', '2025-06-06T17:16:20.865Z', '2025-06-06T17:16:20.865Z');
